// Dergi içeriğini HTML/PDF formatına dönüştür
const content = $input.first().json.output || $input.first().json;
const magazine = content.magazine || content;

function generateHTML(mag) {
  const sections = mag.sections || [];
  let sectionsHTML = '';

  for (const section of sections) {
    const articles = section.articles || [];
    let articlesHTML = articles.map(a => 
      `<article>
        <h3>${a.title || ''}</h3>
        <p>${a.summary || ''}</p>
        <small>Kaynak: ${a.source || ''}</small>
      </article>`
    ).join('\n');

    sectionsHTML += `<section>
      <h2>${section.name || ''}</h2>
      ${articlesHTML}
    </section>\n`;
  }

  return `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    body { font-family: Arial, sans-serif; margin: 40px; line-height: 1.6; }
    .cover { text-align: center; padding: 80px 20px; border-bottom: 3px solid #333; }
    .cover h1 { font-size: 36px; margin-bottom: 10px; }
    .cover h2 { font-size: 24px; color: #666; }
    .toc { margin: 40px 0; }
    .toc ul { list-style: none; padding: 0; }
    .toc li { padding: 8px 0; border-bottom: 1px solid #eee; }
    section { margin: 40px 0; page-break-inside: avoid; }
    section h2 { color: #1a5fb4; border-bottom: 2px solid #1a5fb4; padding-bottom: 10px; }
    article { margin: 20px 0; padding: 20px; background: #f9f9f9; border-radius: 8px; }
    article h3 { margin-top: 0; color: #333; }
    .editor-note { background: #fff3cd; padding: 20px; border-radius: 8px; margin: 40px 0; }
    footer { text-align: center; margin-top: 60px; padding-top: 20px; border-top: 1px solid #eee; color: #666; }
  </style>
</head>
<body>
  <div class="cover">
    <h1>${mag.title || 'OTONOM MEDYA HAFTALIK'}</h1>
    <h2>Sayı #${mag.issue_number || 1} | ${mag.date || ''}</h2>
    ${mag.cover_story ? `<h3>📰 KAPAK: ${mag.cover_story.title}</h3><p>${mag.cover_story.summary}</p>` : ''}
  </div>

  <div class="toc">
    <h2>📋 İÇİNDEKİLER</h2>
    <ul>
      ${sections.map(s => `<li><strong>${s.name}</strong>: ${s.articles?.length || 0} haber</li>`).join('')}
    </ul>
  </div>

  ${sectionsHTML}

  <div class="editor-note">
    <h2>✍️ Editörün Notu</h2>
    <p>${mag.editor_note || ''}</p>
  </div>

  <div>
    <h2>🔮 Gelecek Hafta</h2>
    <p>${mag.next_week_preview || ''}</p>
  </div>

  <footer>
    <p>Otonom Medya Holding | ${mag.date} | Sayı #${mag.issue_number}</p>
    <p>Yapay Zeka tarafından üretildi | İnsan editör onayı ile yayınlandı</p>
  </footer>
</body>
</html>`;
}

const htmlContent = generateHTML(magazine);

return [{
  json: {
    magazine_data: magazine,
    html_content: htmlContent,
    issue_number: magazine.issue_number || 1,
    date: magazine.date || new Date().toISOString().split('T')[0]
  }
}];

// HTML'yi dosyaya kaydet
const fs = require('fs');
const path = require('path');

const magazineDir = '/data/media/magazine';
if (!fs.existsSync(magazineDir)) {
  fs.mkdirSync(magazineDir, { recursive: true });
}

const date = $input.first().json.date || new Date().toISOString().split('T')[0];
const issueNum = $input.first().json.issue_number || 1;
const fileName = `haftalik_${date}_sayi${issueNum}.html`;
const filePath = path.join(magazineDir, fileName);

fs.writeFileSync(filePath, $input.first().json.html_content);

console.log(`Dergi HTML dosyası oluşturuldu: ${filePath}`);

return [{
  json: {
    html_path: filePath,
    html_url: `/media/magazine/${fileName}`,
    issue_number: issueNum,
    date: date
  }
}];

